"""
MKT Christ Commentary — 1 Corinthians chapters 12-14
Run: python3 scripts/zc-christ-1corinthians-12-14.py

Source data used:
- data/interlinear/1corinthians.json
- data/translation/draft/mediating/1corinthians.json

Key Christological decisions for chs 12-14:
- The body of Christ (ch 12) is the primary ecclesiological image: the community
  constituted by Christ's death and resurrection, animated by his Spirit
- The Trinitarian structure of gift-distribution (12:4-6: Spirit/Lord/God) is
  classified as 'direct revelation' — an explicit claim about the Triune God acting
  in the church through gifts
- Agape (ch 13) is the character of God as revealed in Christ crucified; love as
  the greatest gift is Christologically grounded in the self-giving of the Son
- The 'completeness' arriving when the partial ends (13:10) is the Parousia of Christ
- 14:21 quotes Isa 28:11-12 as a shadow fulfilled in the Pentecost phenomenon
- 14:37 Paul's instruction is 'the Lord's commandment' — Christological authority
  grounds apostolic teaching on worship order
- No straight double-quote characters in value strings
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "12": {
    "1": '<p>The chapter opens Paul\'s extended treatment of spiritual gifts (<em>pneumatika</em>) — capacities the Spirit gives for the common good. All these gifts are Christ\'s distributed presence in the body: as the risen Christ ascended and gave gifts to his church (Eph 4:8-11), so the Spirit deploys these capacities in the community as expressions of Christ\'s own ongoing ministry through his body.</p>',
    "2": '<p>The contrast with pagan idolatry — led to mute idols — sets the backdrop for the Spirit\'s speech-gifts. The Spirit who speaks through the community bears witness to the living Christ, whereas the spirits behind idol-worship are silent. The noisy gifts of the Corinthian assembly must be evaluated against this contrast: do they bear witness to the Christ who speaks, or are they ecstatic performance indistinguishable from pagan frenzy?</p>',
    "3": '<p>A direct revelation: no one speaking by the Spirit says \'Jesus be cursed\'; no one can say \'Jesus is Lord\' except by the Spirit. The Lordship confession (<em>Kyrios Iēsous</em>) is the Spirit\'s criterion of authenticity. The risen Christ is Lord — this claim, which contradicts the Roman confession (<em>Kyrios Kaisar</em>, Caesar is Lord), is the test-phrase that only the Spirit of Christ can produce. All genuine spiritual gifts serve this confession and flow from this acknowledgment.</p>',
    "4": '<p>A direct revelation: different gifts, same Spirit. The Trinitarian structure that begins here (vv. 4-6) establishes that all diversity of gifts flows from one divine source. The Spirit who distributes the gifts is the Spirit of Christ (Rom 8:9), so every gift is a participation in Christ\'s own ministry extended through the body. Diversity does not threaten unity because all gifts come from the same Spirit who unites the body to its head.</p>',
    "5": '<p>Different kinds of service (<em>diakoniai</em>), same Lord: the service rendered through spiritual gifts is service to Christ as Lord. All the community\'s ministry is directed toward the one Lord — every prophetic word, every act of service, every healing is an expression of Christ\'s own lordship over the community. The gifts are not the community\'s property but Christ\'s lordship enacted through human instruments.</p>',
    "6": '<p>Different workings (<em>energēmata</em>), same God who works all things in all. The Trinitarian threesome (Spirit, Lord, God) in vv. 4-6 distributes the gifts across all three divine persons — this is not confusion but a description of the Triune God acting as a unified agency through different characteristic modes. The God who created all things (Gen 1) is now creating the new community through Christ\'s Spirit-given gifts.</p>',
    "7": '<p>The manifestation of the Spirit is given to each person for the common good: gifts are not personal spiritual achievements or marks of individual status but communal provisions. The Spirit who manifests through each member does so for the body\'s benefit — a Christological principle, since Christ himself came not to be served but to serve (Mark 10:45). Every genuine gift reproduces this servant-pattern.</p>',
    "8": '<p>The specific gifts (wisdom, knowledge, faith, healing, powers, prophecy, discernment, tongues, interpretation) are the Spirit\'s deployment of Christ\'s own capacities distributed through the body. The message of wisdom and knowledge recall Paul\'s earlier argument that Christ himself is God\'s wisdom (1:30) — through these gifts, Christ\'s own wisdom continues to operate in the community. Each gift is a modality of the risen Christ\'s presence.</p>',
    "9": '<p>Faith and healing gifts: both require trust in the risen Christ\'s power and willingness to act. Gifts of healing in the NT consistently operate in the name of Jesus (Acts 3:6; 4:10; 9:34) — they are not independent charismatic powers but Christ\'s own healing ministry continued through the body. The faith-gift is similarly Christ-dependent: not general religious confidence but the specific trust in Christ\'s resurrection power that enables the impossible.</p>',
    "10": '<p>Prophecy, discernment of spirits, tongues, interpretation: all are forms of Christ\'s own prophetic and revelatory ministry extended through the body. The OT promised that in the messianic age the Spirit would be poured out on all flesh for prophecy (Joel 2:28-29, cited in Acts 2:17-18). These gifts are the fulfillment of that prophetic expectation — Christ\'s Spirit distributing prophetic capacity throughout the community, not just to designated leaders.</p>',
    "11": '<p>One and the same Spirit distributes all gifts to each as he determines: the Spirit\'s sovereignty in gift-distribution prevents any community member from taking credit for possessing a particular gift. The gifts are not earned or developed but given (<em>diairoun idiai</em> — dividing to each individually). This is the anti-boasting principle of 1:30 applied to charismatic life: all gifts are received, none are self-generated.</p>',
    "12": '<p>The body of Christ as the primary ecclesiological image: just as the human body is one while having many members, so Christ is one body comprising many members. The identification <em>houtōs kai ho Christos</em> (so also is Christ) is remarkable — Paul names the body the Christ, not merely Christ\'s body. The community is so thoroughly united with Christ through the Spirit that it can be called Christ himself. This is the strongest possible statement of the community\'s Christological identity.</p>',
    "13": '<p>A direct revelation: we were all baptized by one Spirit into one body — Jews/Gentiles, slaves/free — and given the one Spirit to drink. Baptism into the body of Christ is the Christological act that creates the community\'s unity: the Spirit unites the baptized to Christ and through Christ to each other. The elimination of ethnic and social distinctions (Jews/Greeks, slave/free) is a Christological consequence — in Christ, these distinctions have no ultimate standing (Gal 3:28).</p>',
    "14": '<p>The body is not one part but many: the community\'s diversity is structurally necessary to the body of Christ. A body with only one kind of member cannot function; Christ\'s body requires the full range of gifts and persons to express his complete ministry in the world. Seeking uniformity (everyone should speak in tongues!) contradicts the body\'s nature as Christ constituted it.</p>',
    "15": '<p>If the foot says it does not belong because it is not the hand: the imagined protest of the less conspicuous member reveals the self-undermining logic of gift-comparison. In Christ\'s body, belonging is not determined by the visibility or impressiveness of one\'s gift but by incorporation into the body through the Spirit. Even the least visible member is fully part of Christ\'s body.</p>',
    "16": '<p>The ear claiming it does not belong because it is not an eye: the same logic applied to different members. Every part of Christ\'s body belongs to Christ regardless of its comparative status. The competitive ranking of gifts that the Corinthians practice (tongue-speakers above others) imposes a status-hierarchy onto the body that contradicts its Christological constitution: in Christ, the weak are indispensable.</p>',
    "17": '<p>If the whole body were an eye, where would the hearing be? The body requires difference to function. Applied to the body of Christ: a community where everyone exercises the same gift would lose the comprehensive ministry that Christ\'s body is designed to carry out. The diversity of gifts is not a problem to be solved by uniformity but the Spirit\'s provision for the body\'s complete functioning as Christ\'s presence in the world.</p>',
    "18": '<p>God placed the parts in the body as he wanted them to be: divine intentionality governs the distribution of members and gifts. The body of Christ has the shape God chose, not the shape the Corinthians prefer. Every member\'s placement — and therefore every member\'s gift — is the result of God\'s deliberate design, not random distribution. No gift-holder can claim superiority, since their placement was God\'s choice, not their achievement.</p>',
    "19": '<p>If all were one part, where would the body be? The reduction of the community to a single gift-type (everyone speaks in tongues) would destroy the body\'s capacity to be what Christ\'s body must be: the full expression of his presence and ministry. The body\'s unity is preserved precisely through its diversity.</p>',
    "20": '<p>Many parts, one body: the summary of the body-of-Christ argument. The community\'s unity is not uniformity but organic integration — many different members functioning together as one body. This is the Christological model of unity: the same Christ who is one person with many capacities forms one body from many members.</p>',
    "21": '<p>The eye cannot say to the hand, \'I don\'t need you\': the mutuality of the body\'s parts demolishes any hierarchy of gifts. The most visible gift (prophecy, tongues) needs the gifts of service and administration just as the eye needs the hand. In Christ\'s body, the highest gift is incomplete without the lowest; the most spectacular gift needs the most ordinary to function together.</p>',
    "22": '<p>The weaker parts seem to be indispensable: Paul\'s deliberate reversal of the honor-hierarchy. The apparently weak and unimpressive parts of the body (and, by extension, the community) are the ones God designed as indispensable. This reproduces the cross-pattern: God chose the weak things to shame the strong (1:27). Christ\'s body carries the same cross-logic in its structure — the seemingly marginal are essential.</p>',
    "23": '<p>The less honorable parts treated with special honor: the community gives greater dignity to the members it might be inclined to overlook. This is the social ethics of the body of Christ: rather than reinforcing existing status hierarchies (which would honor the naturally honored and ignore the lowly), the community deliberately honors its weaker members. The cross\'s inversion of honor-hierarchies is enacted in the body\'s mutual care.</p>',
    "24": '<p>God has put the body together giving greater honor to the inferior part: the divine ordering of the body deliberately reverses the world\'s status-assignments. God honors what the world overlooks, just as God honored the crucified Christ whom the world discarded. The body of Christ is structured according to the same reversal-logic as the cross.</p>',
    "25": '<p>No division in the body, equal concern for each other: the telos of the body\'s structure is mutual solidarity. The cross-shaped body of Christ cannot have the status-divisions of Greco-Roman society (patron/client, slave/free) reproduced within it, because these divisions contradict the equal belonging that union with Christ creates. All members belong to the same body and therefore share each other\'s concerns.</p>',
    "26": '<p>If one part suffers, every part suffers with it; if one part is honored, every part rejoices with it: the solidarity of the body of Christ. This is the practical expression of union with Christ: because all members are united in the same body, one member\'s suffering or honor affects all. Paul\'s own suffering (4:9-13) as an apostle is the community\'s suffering; the community\'s flourishing is Paul\'s joy (2 Cor 7:4). The body shares what its members experience.</p>',
    "27": '<p>A direct revelation: you are the body of Christ, and each of you is a part of it. The corporate identification of the community as Christ\'s own body is Paul\'s most concentrated ecclesiological claim. The community is not merely an association of Christ\'s followers — it is the embodiment of the risen Christ in the world. Each member is a specific member of that body, placed by God for a specific function in Christ\'s ongoing ministry.</p>',
    "28": '<p>God has placed in the church: apostles, prophets, teachers, then miracles, healings, helps, administration, tongues. The ordering (first, second, third) does not create a spiritual hierarchy but a functional description of the church\'s life. All these offices and gifts are given by God — placed by God as he chose (v. 18). Apostles first because they are the primary witnesses to the risen Christ (15:1-11); prophets because they speak Christ\'s word to the community; teachers because they transmit the tradition about Christ.</p>',
    "29": '<p>Are all apostles? Are all prophets? Are all teachers? The rhetorical questions demand negative answers: no, each member has their specific role in the body. The universalization of any single gift (everyone should speak in tongues!) contradicts the body\'s design. Christ distributes different gifts to different members so that together they can embody the fullness of his ministry.</p>',
    "30": '<p>Do all have gifts of healing? Do all speak in tongues? Do all interpret? The negative answer to each question deflates the Corinthian enthusiasm for uniformity in the conspicuous gifts. Not all speak in tongues — and this is correct and intentional, not a spiritual deficiency. The body\'s diversity is Christ\'s design, not a temporary imbalance to be corrected by everyone attaining the same gift.</p>',
    "31": '<p>Eagerly desire the greater gifts — and I will show you the most excellent way. Paul\'s pivot to ch 13 reframes the entire discussion: before specifying which gifts are greater, he identifies the way (<em>hodos</em>) that makes all gifts genuinely useful. The most excellent way is not a gift at all but the character of Christ himself — love — without which all gifts are empty. The cross is love\'s definition: Christ gave himself for others, and that self-giving is the pattern every gift must serve.</p>'
  },
  "13": {
    "1": '<p>Without love, the most spectacular gifts are noise. The tongues of men and angels, without love (<em>agapē</em>), are a <em>chalkos echōn</em> (resounding gong) — impressive sound with no communicative substance. The implicit Christological argument: Christ himself is the definition and source of love (1 John 4:8-10; Rom 5:8). Gifts that do not express Christ\'s own character of self-giving love are unfaithful to the one whose Spirit gives them.</p>',
    "2": '<p>If I have prophecy, understand all mysteries and knowledge, have faith that moves mountains, but not love — I am nothing. The gifts of revelation and faith are genuine gifts of the Spirit, but they are not the Spirit\'s ultimate goal. The Spirit\'s goal is conformity to Christ, whose defining act was not miracle-working but self-giving love on the cross. Gifts without love reproduce the Corinthian problem of charismatic performance disconnected from cross-shaped character.</p>',
    "3": '<p>Even giving everything to the poor and surrendering the body to flames, without love — no benefit. The most self-sacrificial behaviors can be performed without the love that is Christ\'s character. Martyrdom without love is a self-performance, not a participation in Christ\'s self-giving. The cross was not a performance of suffering but an act of love — the distinction is everything. Love is the quality that makes any sacrifice genuinely Christ-shaped.</p>',
    "4": '<p>Love is patient, love is kind, does not envy, does not boast, is not proud: the description of love is a description of Christ\'s character. Each quality is exhibited in Christ\'s earthly ministry and supremely in the cross: patient (he endured the cross without retaliation, Heb 12:2), kind (he healed and fed and forgave), not envious (Phil 2:6-7: he did not grasp equality with God), not boastful, not proud (the servant-pattern of Phil 2:5-11). Agape is Christ\'s self-portrait.</p>',
    "5": '<p>Love does not dishonor others, is not self-seeking, is not easily angered, keeps no record of wrongs: the further dimensions of Christ-shaped love. Not self-seeking — Christ\'s kenosis (Phil 2:7: emptied himself, taking the form of a servant) is the ultimate non-self-seeking act. Keeps no record of wrongs — the cross enacts God\'s forgiveness of a world of accumulated sin without keeping account. This is the character that Christ incarnated and that the Spirit produces in those being conformed to Christ.</p>',
    "6": '<p>Love does not delight in evil but rejoices with the truth: love is not morally neutral warmth but alignment with reality as God defines it. Christ himself is the truth (John 14:6) — love that rejoices with the truth is love that rejoices with Christ\'s revelation of reality. The community\'s life is shaped by this truth-love: not the tolerance of falsehood or sin but genuine delight in the good that Christ embodies and enacts.</p>',
    "7": '<p>Always protects, always trusts, always hopes, always perseveres: the four <em>pantote</em> (always) qualities of love mirror the character of God\'s faithfulness to Israel and supremely to humanity in Christ. Protection (<em>stegei</em>): love covers, as Christ\'s atonement covers sin (1 Pet 4:8). Trust: love maintains relational confidence as Christ maintains the believer before the Father. Hope: love anticipates the eschatological fulfillment Christ will bring. Perseverance: as Christ endured the cross (Heb 12:2), love endures all things.</p>',
    "8": '<p>Love never fails. Prophecy, tongues, and knowledge will cease: the eschatological permanence of love contrasts with the provisional nature of the gifts. Gifts are given for the period between resurrection and Parousia; they serve the community\'s life in the <em>already-not-yet</em>. When Christ returns and ushers in the fullness of the new creation, prophetic words will be superseded by direct vision, tongues by the universal language of the new humanity, partial knowledge by full knowing. Only love continues, because love is God\'s own nature (1 John 4:8).</p>',
    "9": '<p>We know in part and prophesy in part: the radical limitation of all present-age knowledge and prophecy. The gifts of revelation are genuine but incomplete — partial disclosures of a reality that will only be fully known when Christ is fully revealed. This epistemic humility is Christological: we see Christ now through the proclamation and Spirit\'s witness; then we will see him face to face (v. 12). Present gifts serve the partial; the Parousia will bring the complete.</p>',
    "10": '<p>When completeness (<em>to teleion</em>) comes, the partial will pass away: the arrival of Christ at the Parousia is the coming of completeness. The gifts are provisional provisions for the period of Christ\'s bodily absence; when he returns, the community will no longer need prophetic mediation or partial revelation. The completion is Christ himself: knowing fully as we are fully known (v. 12) means the personal knowledge of the face-to-face encounter with the risen Lord.</p>',
    "11": '<p>When I was a child I thought like a child; when I became an adult I set aside childish things: the developmental metaphor frames the transition from partial to complete knowledge. The maturity that comes with Christ\'s return is not merely greater knowledge but a qualitative transformation — from mediated partial disclosure to immediate personal encounter. The child\'s world is real but limited; the fullness of Christ\'s coming will make the present gifts appear as preparation rather than destination.</p>',
    "12": '<p>Now we see through a mirror dimly; then face to face. Now I know in part; then I shall know fully as I am fully known. The mirror-metaphor captures the indirect, reflected quality of present Christological knowledge. Ancient mirrors gave dim, imperfect reflections. The Parousia brings direct vision: face to face — the language of intimate personal encounter (cf. Exod 33:11: Moses spoke with YHWH face to face). The fully-known is fully Christological: God who fully knows us in Christ will be fully known by us in Christ.</p>',
    "13": '<p>Faith, hope, and love abide — the greatest is love. The three theological virtues that characterize the present age continue into the eschatological future, but love is greatest because it is the nature of God himself. Faith will not be abolished at the Parousia but completed in sight; hope will not be abolished but filled in possession; love alone has no eschatological limit, because God himself is love and his kingdom is defined by love\'s full expression. The love Paul describes is the love poured into our hearts by the Spirit (Rom 5:5) — participation in God\'s own trinitarian love.</p>'
  },
  "14": {
    "1": '<p>Follow the way of love and desire spiritual gifts, especially prophecy: love and gifts are not alternatives but companions. The most excellent way (13:1) is the way that properly orients gifts. Prophecy is highlighted because it builds up the community (v. 3) — the standard of Christ-shaped self-giving love is fulfilled more directly by prophecy than by tongues. The criterion of genuine gift-use is whether it builds up the body of Christ.</p>',
    "2": '<p>The tongue-speaker speaks to God, not to people: tongues are a form of Spirit-mediated prayer directed vertically. The utterances are mysteries (<em>mystēria</em>) addressed to God — genuine communication between the believer\'s spirit and God, but not comprehensible to other members of the body. This is not disparagement of tongues but specification of their scope: they serve the individual\'s relationship with God, not the community\'s corporate instruction in Christ.</p>',
    "3": '<p>The prophet speaks to people for strengthening, encouragement, and comfort: prophecy serves the body of Christ directly. All three purposes (<em>oikodomē, paraklēsis, paramythia</em>) describe what Christ himself does for his people through the Spirit (John 14:16-17: the Paraclete will strengthen and encourage). Prophecy is an extension of Christ\'s own ongoing ministry of strengthening his community through Spirit-inspired speech.</p>',
    "4": '<p>Tongues build up the self; prophecy builds up the church: the distribution of gifts\' scope. Both are genuine gifts but with different primary referents. The self-edification of tongues is real and valid (Paul values it, v. 18) but secondary to the community-building that is the body of Christ\'s primary calling. The love-criterion requires preferring the gift that serves others over the gift that primarily serves self.</p>',
    "5": '<p>Paul wishes all spoke in tongues but prefers prophecy: both gifts are good; one is more useful for the body. The prophetic gift is preferred not because it is higher on a spiritual scale but because it more directly serves the community\'s formation in Christ. The person who prophesies is greater in terms of community-benefit (not personal spiritual status) — a consistently applied love-criterion.</p>',
    "6": '<p>What good is unintelligible speech? If Paul came speaking only in tongues, he would not benefit the community without revelation, knowledge, prophecy, or teaching. All four of these communicative modes transmit the content of Christ — his teaching, his acts, his significance, his call. Genuine apostolic ministry must communicate intelligibly because the content (Christ crucified and risen) must be understood, not merely experienced as ecstatic sound.</p>',
    "7": '<p>Even lifeless instruments must produce distinct tones to communicate: the flute and harp must play recognizable notes, or their sound is meaningless. The musical analogy establishes the principle that communication requires intelligibility. Spirit-given speech in the community must transmit the recognizable melody of the gospel — the intelligible content of Christ\'s person and work — not merely produce spiritual sound.</p>',
    "8": '<p>The trumpet must sound a clear call for battle preparation: the military analogy sharpens the intelligibility requirement. An unclear trumpet-call before battle is dangerous, not merely unhelpful. Unintelligible speech in the community similarly fails in the moment when the community needs clear direction. The call to rally around Christ must be sounded clearly for the community to respond faithfully.</p>',
    "9": '<p>Unless you speak intelligible words, you are speaking into the air: the negative statement of the intelligibility requirement. The Spirit\'s purpose in giving speech-gifts is that the community might be built up in Christ — this requires comprehension. Speech directed nowhere is wasted; speech that conveys Christ\'s gospel finds its mark.</p>',
    "10": '<p>Many languages in the world, all meaningful: the linguistic observation grounds the analogy. Every human language, however foreign to others, has genuine semantic content — there is no tongue without meaning. The parallel with spiritual gifts: all genuine Spirit-given speech has real content (communication with God), but content without comprehension by hearers does not serve the community.</p>',
    "11": '<p>A foreigner to the speaker and the speaker a foreigner to me: mutual incomprehension as the failure-mode of gift-use without love. If tongue-speech creates foreignness within the body of Christ — the community defined by the removal of ethnic and social boundaries (12:13) — it is working against the body\'s Christological constitution.</p>',
    "12": '<p>Excel in gifts that build up the church: the governing criterion for gift-seeking. The desire for spiritual gifts must be ordered by the love-criterion — seek those gifts that serve the community\'s formation in Christ. This is not a hierarchy of gifts in the abstract but a community-situational priority: what the body of Christ needs most is what deserves most emphasis.</p>',
    "13": '<p>The tongue-speaker should pray for the gift of interpretation: the solution to the tongues-without-intelligibility problem. If the tongue-speaker can also interpret, the vertical communication with God can become horizontal community-instruction. The gift of interpretation transforms private prayer-speech into communal edification — it serves the body by making the Spirit\'s communication with God accessible to the whole community.</p>',
    "14": '<p>If I pray in a tongue my spirit prays but my mind is unengaged: the genuine phenomenon of Spirit-mediated prayer that bypasses ordinary cognitive processing. Paul does not dismiss this — his spirit is genuinely praying — but he identifies its limitation: the mind\'s disengagement means others cannot participate. The individual\'s spiritual experience, however genuine, does not automatically constitute the community\'s edification.</p>',
    "15": '<p>I will pray with the spirit and with the mind; sing with the spirit and with the mind: Paul\'s integrated worship practice. Both dimensions are necessary: the spirit\'s direct engagement with God (pneumatic prayer) and the mind\'s comprehending participation (intelligible prayer). Christ himself worshipped with full integration — his prayers in Gethsemane were both deeply Spirit-moved and fully articulate. Christian worship reflects this wholeness.</p>',
    "16": '<p>If you are praising God in the Spirit, how can the uninitiated say Amen? The <em>Amen</em> (so be it, truly) is the community\'s participatory ratification of the prayer — a liturgical practice inherited from the Jewish synagogue. The Spirit-led worshipper speaking only in tongues excludes the unlearned participant from joining their ratification to the prayer. The community\'s worship must enable everyone\'s participation, not just the gifted individual\'s expression.</p>',
    "17": '<p>You are giving thanks well enough but no one else is built up: the distinction between genuine personal piety and communal edification. The tongue-speaker is genuinely giving thanks to God — the act is real and valuable. But genuine individual worship does not automatically create communal edification. The love-criterion requires attending to both: the individual\'s spirit-prayer and the community\'s ability to participate.</p>',
    "18": '<p>I thank God that I speak in tongues more than all of you: Paul\'s personal affirmation of the tongues-gift. This establishes that Paul\'s preference for prophecy in the community setting is not born of personal inexperience with tongues. He has the gift abundantly and values it privately. His argument is about communal context, not personal spirituality — tongues are valuable; they just serve the community most when accompanied by interpretation.</p>',
    "19": '<p>In the church I would rather speak five intelligible words to instruct others than ten thousand words in tongues: the stark numerical contrast makes the priority clear. Instruction in Christ requires comprehensible communication. The ten-thousand-word tongue may be genuine Spirit-expression; the five-word instruction may seem modest; but the community\'s formation in Christ requires the five intelligible words. Quality of service over quantity of spiritual expression.</p>',
    "20": '<p>Do not think like children; in regard to evil be infants, but in your thinking be mature (<em>teleioi</em>): the maturity of understanding that the Parousia will bring (13:10) must already begin to characterize the community\'s practical wisdom. The Corinthians\' elevation of tongues over prophecy is an immature evaluation — seeing the spectacular gift as superior without understanding the community-building criterion. Mature Christological discernment evaluates gifts by their service to the body, not their impressiveness.</p>',
    "21": '<p>A shadow: Paul cites Isa 28:11-12 (LXX) — with other tongues and foreign lips God will speak to this people, and even then they will not listen. Isaiah\'s oracle was a judgment-sign: foreign invaders\' unintelligible speech would be the sign of God\'s judgment on Israel for not hearing his prophetic word. Paul applies it as a shadow fulfilled in the tongues-phenomenon: tongues-without-interpretation in the assembly serves as a judgment-sign to unbelievers (v. 22), not as the primary mode of community instruction. The OT judgment-sign pattern reverberates in the Corinthian misuse of tongues.</p>',
    "22": '<p>Tongues are a sign for unbelievers; prophecy for believers: the asymmetric function of the gifts. Tongues function as a sign to unbelievers — possibly a conviction-sign (the divine breaking in) or a judgment-sign (incomprehension echoing Isa 28). Prophecy serves the community that believes. The sign-function of tongues recalls the OT pattern of signs-for-the-unbelieving (Exod 7-12; Isa 7:14) — extraordinary phenomena that testify to divine activity for those who lack faith\'s inner reception.</p>',
    "23": '<p>If the whole church speaks in tongues and unbelievers come in, they will say you are out of your minds: the practical consequence of unregulated tongues. The uninitiated observer cannot distinguish Spirit-inspired speech from pagan frenzy — without interpretation, the community\'s worship looks like ecstatic disorder. This undermines the mission of the body of Christ in the world: the community that looks mad cannot effectively witness to the rational, coherent Lord who called it into being.</p>',
    "24": '<p>But if an unbeliever comes in while everyone is prophesying, they are convicted and called to account: prophecy\'s evangelistic power. When the community speaks intelligibly in Christ\'s name — clarifying the human situation before God, naming sin and grace — the unbeliever\'s conscience is engaged. Conviction (<em>elegchetai</em>) and examination (<em>anakrinetai</em>) are Spirit-mediated encounters with Christ\'s truth applied to the observer\'s life.</p>',
    "25": '<p>The secrets of the heart laid bare, the unbeliever falling down and worshipping God: prophecy can create the encounter with the living God that results in worship. The falling down (<em>pesōn epi prosōpon</em>) is the OT posture of encounter with the divine (Isa 6:5; Ezek 1:28). When prophetic speech makes Christ\'s reality visible to the unbeliever, the result is the same as any genuine theophany — prostration and the confession \'God is really among you.\'</p>',
    "26": '<p>When you come together, each person has a hymn, instruction, revelation, tongue, or interpretation: the ordered diversity of the community\'s gathered worship. All contributions serve the single criterion: <em>panta pros oikodomēn ginesthō</em> (let everything be done for building up). The community gathers as the body of Christ, and every contribution should build up that body. The common good (12:7) and the building up of the church (14:4-5) are the same criterion.</p>',
    "27": '<p>If anyone speaks in a tongue, two or at most three, one at a time, with someone to interpret: the regulations for orderly tongues-use. The limits (two or three, in sequence, with interpretation) ensure that tongues serve the community rather than overwhelming it. Christ\'s body functions as an organized body, not as chaotic noise. The Spirit who gives the gifts also gives the self-control to use them within order.</p>',
    "28": '<p>If there is no interpreter, the tongue-speaker should keep quiet and speak to himself and to God: the community\'s edification takes priority over the individual\'s gift-expression. The tongue-speaker is not silenced absolutely — private prayer in tongues continues — but the public setting requires intelligibility. The community gathered as Christ\'s body needs what the body can receive, not what the individual spirit yearns to express.</p>',
    "29": '<p>Two or three prophets should speak, and the others should weigh carefully what is said (<em>diakrinetōsan</em>): prophecy is subject to communal discernment. No prophetic word is above evaluation — even genuine Spirit-inspired speech must be tested against the body\'s discernment. This is the community exercising the mind of Christ (2:16): judging all things (2:15), testing every spirit (1 John 4:1), holding fast to what is good (1 Thess 5:21).</p>',
    "30": '<p>If a revelation comes to someone sitting down, the first speaker should stop: the Spirit\'s freedom to speak through different members requires the community\'s flexibility. No individual prophet has exclusive access to revelation during the gathering; the Spirit distributes revelatory capacity as he determines (12:11). Yielding to another\'s revelation is an act of the love that does not insist on its own way (13:5).</p>',
    "31": '<p>All can prophesy in turn so that everyone may be instructed and encouraged: the universal potential of Spirit-mediated prophetic speech. Prophecy is not the exclusive property of designated leaders but the Spirit\'s gift given as he wills across the community. The goal — instruction and encouragement of everyone — is the body-building purpose that governs the entire chapter.</p>',
    "32": '<p>The spirits of prophets are subject to the control of prophets: Spirit-given capacities do not override the individual\'s will or rationality. The Spirit who gives the gift does not compel uncontrolled expression; the prophet retains agency. This directly contradicts the pagan model of possession (where the god overwhelmed the person); in the Spirit\'s economy, the gift-recipient remains a responsible agent. The Spirit of Christ creates order and self-control (Gal 5:22-23: the fruit of the Spirit includes self-control).</p>',
    "33": '<p>God is not a God of disorder but of peace: the Christological grounding of worship order. God\'s own character — not social convenience or Roman institutional norms — is the reason for orderly worship. Peace (<em>eirēnē</em>) is one of the Spirit\'s fruits (Gal 5:22) and one of Christ\'s primary gifts to the community (John 14:27; 20:19-21). Worship that reflects God\'s character will be marked by the same peace that Christ gives.</p>',
    "34": '<p>Women should remain silent in the churches: this instruction — understood in its immediate context as a specific regulation about weighing prophetic speech (vv. 29-33) rather than a universal prohibition on women speaking — grounds the community\'s practice in the order (<em>taxis</em>) appropriate to the assembly of God\'s people. The interpretation of this verse must be read with 11:5 (women praying and prophesying) and Gal 3:28 (neither male nor female in Christ). Whatever the specific situation Paul addresses, the principle remains: the gathering of Christ\'s body requires order that serves the community\'s formation.</p>',
    "35": '<p>If they want to inquire about something, let them ask their own husbands at home: the specific pastoral instruction governing the disruption of worship by questions during the weighing of prophecy. The instruction is situationally specific (wives and husbands in the assembly) and practically oriented — the gathered community cannot function as a tutorial session during the prophetic evaluation process. Domestic inquiry maintains the assembly\'s Christological purpose.</p>',
    "36": '<p>Did the word of God originate with you? Or are you the only people it has reached? Paul\'s rhetorical challenge to Corinthian exceptionalism. The community in Corinth is part of the wider body of Christ whose practice in all the congregations (v. 33) should be consistent. No single community has the authority to override the universal apostolic teaching about worship order, since the word that constitutes the community came to them, not from them.</p>',
    "37": '<p>If anyone thinks they are a prophet or spiritually gifted, let them acknowledge that what I am writing is the Lord\'s commandment (<em>Kyriou entolē</em>): Paul explicitly grounds his worship instructions in Christ\'s own authority. The regulations about tongues, prophecy, and order are not merely Pauline preference but the Lord\'s commandment — carrying the authority of the one who is Lord over his own body and its gatherings. Prophets who reject Paul\'s instructions thereby reject the Lord whose word Paul transmits.</p>',
    "38": '<p>If anyone ignores this, they will be ignored: the eschatological consequence of rejecting the Lord\'s commandment about worship. To ignore the instruction about how Christ\'s body gathers is to ignore Christ himself — and the verb <em>agnoeitō</em> (let them be unknown) may carry the force of being unknown to the Lord at the final reckoning (cf. Matt 7:23: I never knew you). The stakes of correct worship are ultimately Christological.</p>',
    "39": '<p>Eagerly desire to prophesy, and do not forbid speaking in tongues: Paul\'s positive summary. Both gifts are valid; both are to be sought. The emphasis on prophecy is not a prohibition of tongues but a prioritization within the community setting. The body of Christ is enriched by the full range of Spirit-given speech; the community\'s life requires all these gifts exercised with love and order.</p>',
    "40": '<p>But everything should be done in a fitting and orderly way: the capstone of the entire discussion of gifts. <em>Euschēmonōs kai kata taxin</em> (fittingly and in order) — the community\'s worship must reflect the God of peace (v. 33) and the love that keeps all things in good order (13:5-6). The body of Christ gathering in worship enacts its identity as Christ\'s body when its gifts are exercised in the love and order that Christ himself embodies and the Spirit produces.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', '1corinthians')
    merge_comm(existing, CHRIST)
    save_comm('mkt-christ', '1corinthians', existing)
    for ch in ['12', '13', '14']:
        count = len(existing.get(ch, {}))
        print(f'  ch{ch}: {count} entries')

if __name__ == '__main__':
    main()
